import { useState, useEffect, useCallback } from 'react';

export interface FormValues {
  [key: string]: any;
}

export interface UseFormOptions<T extends FormValues> {
  defaultValues: T;
  onSubmit?: (values: T) => void;
}

export interface UseFormReturn<T extends FormValues> {
  values: T;
  errors: Partial<Record<keyof T, string>>;
  touched: Partial<Record<keyof T, boolean>>;
  handleChange: (name: keyof T) => (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => void;
  handleBlur: (name: keyof T) => () => void;
  handleSubmit: (e?: React.FormEvent) => void;
